var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"같은 시간","JPN":"同時刻","ENG":"Meanwhile","TWN":"同一時間","SCN":"同一时间","DEU":"Meanwhile","FRA":"Meanwhile"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>로터스</color> 아마니 밸리\\n관리국 본부, 제3부설 격납고","JPN":"管理局直轄都市<color=#ffd34c>ロータス</color>アマニーバレー\\n管理局本部、第3付属格納庫","ENG":"[[","TWN":"管理局直轄市 <color=#ffd34c>洛德斯</color> 阿瑪尼山谷\\n管理局總部附設第3機庫","SCN":"管理局直属城市<color=#ffd34c>洛德斯</color>阿玛尼谷\\n管理局总部，第3附属机库","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"퓨처 앳 워에 관한 중요한 문제라더니…….","JPN":"フューチャーアットウォーに関する重要な問題と言うから来てみたら……","ENG":"So this Future-at-War matter you said was important...","TWN":"說是關於天啟兵器的重要問題……"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"최고 관리자, 당신 설마… 저것 때문에 나를 이리로 부른 거였어?","JPN":"最高管理者、まさか……あれのために呼んだのか？","ENG":"Supreme Administrator, don't tell me... this is why you called me here?","TWN":"最高管理者，難道……你是因為那個才把我叫到這裡來的嗎？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇다네. 자네를 이곳에 부른 첫번째 이유는…….","JPN":"ああ。君をここに呼んだ1つ目の理由は……","ENG":"That is correct. The first reason I summoned you here is...","TWN":"是的。找你到這裡的第一個原因是……"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>코핀 컴퍼니 압류 대상 9호</color>의 사용허가를 받기 위함이었네.","JPN":"<color=#ffd34c>コフィンカンパニー差し押さえ対象9号</color>の使用許可を出してもらうためだ。","ENG":"...to obtain authorization to use <color=#ffd34c>Coffin Company Seized Asset No. 9</color>.","TWN":"希望得到<color=#ffd34c>科芬公司扣押物件第9號</color>的使用許可。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"하하하! 안녕하신가…! 모두 잘 부탁한다네……!","JPN":"ははは！　久しぶりだな……！　皆よろしく頼むぞ！","ENG":"Ha ha ha! Greetings...! I look forward to working with you all...!","TWN":"哈哈哈！你們好……！請大家多多關照……！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"하도 오랜만에 움직여서 그런지, 이거 온몸이 삐걱거리는구만……!","JPN":"久しぶりすぎるせいか、全身がギクシャクするな……！","ENG":"Been so long since I moved, my whole frame creaks with every step...!","TWN":"可能是因為太久沒動，渾身關節都在嘎吱作響……！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"고작 압류품의 사용 허가를 받으려고, 시니어를 여기까지 불렀다고?","JPN":"たかが差し押さえ品の使用許可程度で、シニアをここまで呼び出しただと？","ENG":"You dragged a Senior all the way out here just to authorize a seized asset?","TWN":"只因為要拿到使用扣押物品的許可，竟然把Senior叫到這裡來？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"……웃기지 마, 당신.","JPN":"……ふざけるなよ。","ENG":"...Don't make me laugh.","TWN":"……你在跟我開玩笑嗎！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"저 고철 덩어리를 또다시 내 눈 앞에 들이민 것 자체가 의도가 뻔하잖아?","JPN":"あの鉄くずを私の前に出してくることからして、意図が見え透いている！","ENG":"Parading that pile of scrap in front of me again makes your intent obvious enough.","TWN":"你又把那堆廢鐵放到我面前，意圖已經很明顯了不是嗎？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"당신 대체 뭐야? 날 모른다고 할 때는 언제고… 이제 와서 대체 무슨 짓거리야……?","JPN":"あなた、一体何のつもりだ？　私のことをよく知らないと言ってたくせに……今さら何をするつもりだ？","ENG":"What are you really after? First you pretended not to know me... and now this farce?","TWN":"你到底是什麼人？之前還說不認識我…現在又在搞什麼鬼……？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이거 미안하게 됐군, 르네 말루프 양.","JPN":"すまないな、ルネ・マルーフ君。","ENG":"My apologies, Renée Maalouf.","TWN":"真是抱歉了，芮妮·瑪盧夫。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네와 처음 만나게 된 뒤로, 자네에 대해서 알고 싶어졌거든.","JPN":"君と初めて出会ってから、君について知りたくなったのだ。","ENG":"After meeting you, I found myself wanting to know more about you.","TWN":"自從和你第一次見面後，我就很想瞭解你。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래서 내 나름대로 조사를 했네.","JPN":"それで、私なりに調べさせてもらったよ。","ENG":"So I made some inquiries on my own.","TWN":"所以我自己做了一些調查。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네가 최연소로 퓨처 앳 워 프로젝트에 발탁되었다는 것…….","JPN":"君が最年少でフューチャーアットウォーに抜擢されていたこと……","ENG":"I learned you were the youngest ever selected for the Future-at-War project...","TWN":"你是以最年輕的身份被選入天啟兵器計畫的……"},"stage":{"bg":"DOCUMENTS","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네가 한 때 <color=#ffd34c>타이탄 프로젝트</color>에 참여했다는 것…….","JPN":"君がかつては<color=#ffd34c>タイタンプロジェクト</color>に参加していたこと……","ENG":"That you once participated in the <color=#ffd34c>Titan Project</color>...","TWN":"你曾經參與過<color=#ffd34c>泰坦計畫</color>……"},"stage":{"bg":"DOCUMENTS","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 자네 팀이 무인 병기 전력을 혁신적으로 끌어올리기 위해.","JPN":"そして君のチームが無人兵器戦力を革新的に引き上げるために……","ENG":"And that your team sought to revolutionize unmanned weapons capability...","TWN":"而且為讓你的團隊能夠提升無人兵器的戰力，"},"stage":{"bg":"DOCUMENTS","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>체르노프</color> 박사에게 제안했었지만, 결국 반려되었던 타이탄의 <color=#ffd34c>시제안</color>이 존재한다는 것.","JPN":"<color=#ffd34c>チェルノフ</color>博士に提案したものの結局却下されてしまった、タイタンの<color=#ffd34c>試案</color>があるということが分かった。","ENG":"...by proposing a <color=#ffd34c>prototype</color> to Dr. <color=#ffd34c>Chernov</color>, though it was ultimately rejected.","TWN":"<color=#ffd34c>切爾諾夫</color>博士曾經提議過，但最終被否決的泰坦<color=#ffd34c>試製案</color>確實存在。"},"stage":{"bg":"DOCUMENTS","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"……<color=#ffd34c>주피터 플랜</color>.","JPN":"……<color=#ffd34c>ジュピタープラン</color>。","ENG":"...The <color=#ffd34c>Jupiter Plan</color>.","TWN":"……<color=#ffd34c>木星計畫</color>."},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"20년이나 지나 버린… 그 과거의 유산을, 이제 와서 나보고 재현하라고?","JPN":"20年も過ぎた……過去の遺産を、今更私に再現しろと？","ENG":"You want me... to recreate a relic from twenty years ago now?","TWN":"現在讓我重現那已經過去20年的遺產？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇다네, 르네 양.","JPN":"そうだよ、ルネ君。","ENG":"That is correct, Renée.","TWN":"是的，芮妮。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이 세계를 지키기 위해서 말이지.","JPN":"この世界を守るためにね。","ENG":"To safeguard this world.","TWN":"為了守護這個世界。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"당신, 대체 무슨 생각이야!","JPN":"一体何を考えているんだ！","ENG":"What in the world are you thinking?!","TWN":"你到底在想什麼！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그때는 철이 없었지만, 이제는 나도 박사님께서 왜 그 시제안을 폐기했는지는 알아.","JPN":"あの頃の私はまだ未熟で、博士が何故あの試案を破棄したのか理解できなかった……だが今は分かる。","ENG":"I was naive back then, but now I understand why Dr. Chernov scrapped it.","TWN":"那時候我還不懂事，但現在我知道博士為什麼要放棄那個提案了。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"주피터 플랜은 그저 이상론이었을 뿐, 실현 가능성 따위 없는 페이퍼 플랜이었으니까.","JPN":"ジュピタープランはただの理想論にすぎず、実現可能性などないペーパープランだった。","ENG":"The Jupiter Plan was nothing but idealism. It was an unworkable paper scheme.","TWN":"木星計畫不過是個理想論，只是個沒有實現可能性的紙上談兵而已。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"하물며 당시에는 타이탄 프로젝트조차 불분명한 상황이었어.","JPN":"それに、当時はタイタンプロジェクト自体も、そもそも不安定な状況で……","ENG":"Back then, even the Titan Project itself was still uncertain.","TWN":"更何況當時連泰坦計畫都不明確。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그러니까… 체르노프 박사님께서는…….","JPN":"だから……チェルノフ博士は……","ENG":"So of course... Dr. Chernov–","TWN":"所以……切爾諾夫博士才……"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};